mapper.select:
SELECT s.submission_id, s.homework_id, h.title AS homework_title, h.deadline, s.student_id, us.name AS student_name, us.username AS student_username, s.submit_content, s.status, s.score, s.teacher_comment, ug.name AS graded_by_name, s.submit_time, s.graded_time FROM biz_homework_submission s LEFT JOIN biz_homework h ON h.homework_id = s.homework_id LEFT JOIN sys_user us ON us.user_id = s.student_id LEFT JOIN sys_user ug ON ug.user_id = s.graded_by WHERE s.homework_id = #{homeworkId} AND s.del_flag = '0'
AND s.status = #{status}
ORDER BY s.submit_time ASC
